use fastly::http::{header, Method, StatusCode};
use fastly::{Backend, Body, Error, Request, Response};
use std::time::Duration;

const BACKEND_PRIMARY: &str = "primary_backend";
const BACKEND_SECONDARY: &str = "secondary_backend";
const BACKEND_API: &str = "api_backend";

#[derive(Clone, Debug)]
struct BackendConfig {
    name: &'static str,
    host: &'static str,
    port: u16,
    sni_hostname: &'static str,
    use_tls: bool,
    connect_timeout_ms: u64,
    first_byte_timeout_ms: u64,
    between_bytes_timeout_ms: u64,
}

impl BackendConfig {
    fn new(
        name: &'static str,
        host: &'static str,
        port: u16,
        sni_hostname: &'static str,
        use_tls: bool,
    ) -> Self {
        BackendConfig {
            name,
            host,
            port,
            sni_hostname,
            use_tls,
            connect_timeout_ms: 10000,
            first_byte_timeout_ms: 15000,
            between_bytes_timeout_ms: 10000,
        }
    }

    fn with_timeouts(
        mut self,
        connect_ms: u64,
        first_byte_ms: u64,
        between_bytes_ms: u64,
    ) -> Self {
        self.connect_timeout_ms = connect_ms;
        self.first_byte_timeout_ms = first_byte_ms;
        self.between_bytes_timeout_ms = between_bytes_ms;
        self
    }
}

fn get_backend_configs() -> Vec<BackendConfig> {
    vec![
        BackendConfig::new(
            BACKEND_PRIMARY,
            "www.example.com",
            443,
            "www.example.com",
            true,
        )
        .with_timeouts(5000, 15000, 10000),
        BackendConfig::new(
            BACKEND_SECONDARY,
            "static.example.com",
            443,
            "static.example.com",
            true,
        )
        .with_timeouts(5000, 10000, 5000),
        BackendConfig::new(
            BACKEND_API,
            "api.example.com",
            443,
            "api.example.com",
            true,
        )
        .with_timeouts(3000, 30000, 15000),
    ]
}

fn resolve_backend(req: &Request) -> Option<BackendConfig> {
    let path = req.get_path();
    let configs = get_backend_configs();

    if path.starts_with("/api/") || path.starts_with("/v1/") || path.starts_with("/v2/") {
        configs.into_iter().find(|c| c.name == BACKEND_API)
    } else if path.starts_with("/static/")
        || path.starts_with("/assets/")
        || path.starts_with("/images/")
        || path.starts_with("/css/")
        || path.starts_with("/js/")
    {
        configs.into_iter().find(|c| c.name == BACKEND_SECONDARY)
    } else {
        configs.into_iter().find(|c| c.name == BACKEND_PRIMARY)
    }
}

fn build_backend(config: &BackendConfig) -> Backend {
    let mut builder = Backend::builder(config.name, config.host)
        .override_host(config.host)
        .connect_timeout(Duration::from_millis(config.connect_timeout_ms))
        .first_byte_timeout(Duration::from_millis(config.first_byte_timeout_ms))
        .between_bytes_timeout(Duration::from_millis(config.between_bytes_timeout_ms));

    if config.use_tls {
        builder = builder
            .enable_ssl()
            .ssl_min_version(fastly::backend::TlsVersion::Tls12)
            .ssl_max_version(fastly::backend::TlsVersion::Tls13)
            .sni_hostname(config.sni_hostname)
            .cert_hostname(config.sni_hostname);
    }

    builder = builder.port(config.port);

    builder.finish().expect("Failed to build backend")
}

fn send_to_backend(mut req: Request, config: &BackendConfig) -> Result<Response, Error> {
    req.set_header(header::HOST, config.host);
    req.set_header("X-Forwarded-Host", req.get_url().host_str().unwrap_or(""));
    req.set_header("X-Backend-Name", config.name);

    let backend = build_backend(config);

    match req.send(backend) {
        Ok(mut resp) => {
            resp.set_header("X-Served-By", config.name);
            resp.set_header("X-Backend-Host", config.host);
            Ok(resp)
        }
        Err(e) => {
            eprintln!(
                "Error sending request to backend {}: {:?}",
                config.name, e
            );
            Ok(Response::from_status(StatusCode::BAD_GATEWAY)
                .with_header(header::CONTENT_TYPE, "text/html; charset=utf-8")
                .with_body(format!(
                    "<html><body><h1>502 Bad Gateway</h1><p>Backend '{}' is unavailable.</p></body></html>",
                    config.name
                )))
        }
    }
}

fn handle_health_check() -> Response {
    Response::from_status(StatusCode::OK)
        .with_header(header::CONTENT_TYPE, "application/json")
        .with_body(r#"{"status":"healthy","service":"edge-router"}"#)
}

fn handle_not_found() -> Response {
    Response::from_status(StatusCode::NOT_FOUND)
        .with_header(header::CONTENT_TYPE, "text/html; charset=utf-8")
        .with_body("<html><body><h1>404 Not Found</h1></body></html>")
}

fn handle_method_not_allowed() -> Response {
    Response::from_status(StatusCode::METHOD_NOT_ALLOWED)
        .with_header(header::CONTENT_TYPE, "text/html; charset=utf-8")
        .with_header(header::ALLOW, "GET, POST, PUT, DELETE, PATCH, HEAD, OPTIONS")
        .with_body("<html><body><h1>405 Method Not Allowed</h1></body></html>")
}

fn add_security_headers(resp: &mut Response) {
    resp.set_header("X-Content-Type-Options", "nosniff");
    resp.set_header("X-Frame-Options", "DENY");
    resp.set_header("X-XSS-Protection", "1; mode=block");
    resp.set_header(
        "Strict-Transport-Security",
        "max-age=31536000; includeSubDomains",
    );
    resp.set_header("Referrer-Policy", "strict-origin-when-cross-origin");
}

fn add_cache_headers(resp: &mut Response, path: &str) {
    if path.starts_with("/static/")
        || path.starts_with("/assets/")
        || path.starts_with("/images/")
        || path.starts_with("/css/")
        || path.starts_with("/js/")
    {
        resp.set_header(
            header::CACHE_CONTROL,
            "public, max-age=86400, stale-while-revalidate=3600",
        );
    } else if path.starts_with("/api/") {
        resp.set_header(header::CACHE_CONTROL, "no-store, no-cache, must-revalidate");
        resp.set_header(header::PRAGMA, "no-cache");
    } else {
        resp.set_header(
            header::CACHE_CONTROL,
            "public, max-age=300, stale-while-revalidate=60",
        );
    }
}

fn handle_request(req: Request) -> Result<Response, Error> {
    let path = req.get_path().to_string();
    let method = req.get_method().clone();

    // Health check endpoint
    if path == "/health" || path == "/healthcheck" {
        return Ok(handle_health_check());
    }

    // Validate allowed methods
    match method {
        Method::GET
        | Method::POST
        | Method::PUT
        | Method::DELETE
        | Method::PATCH
        | Method::HEAD
        | Method::OPTIONS => {}
        _ => return Ok(handle_method_not_allowed()),
    }

    // Handle CORS preflight
    if method == Method::OPTIONS {
        let mut resp = Response::from_status(StatusCode::NO_CONTENT);
        resp.set_header("Access-Control-Allow-Origin", "*");
        resp.set_header(
            "Access-Control-Allow-Methods",
            "GET, POST, PUT, DELETE, PATCH, HEAD, OPTIONS",
        );
        resp.set_header(
            "Access-Control-Allow-Headers",
            "Content-Type, Authorization, X-Requested-With",
        );
        resp.set_header("Access-Control-Max-Age", "86400");
        return Ok(resp);
    }

    // Resolve backend based on request path
    let backend_config = match resolve_backend(&req) {
        Some(config) => config,
        None => return Ok(handle_not_found()),
    };

    println!(
        "Routing {} {} to backend '{}' ({}:{})",
        method, path, backend_config.name, backend_config.host, backend_config.port
    );

    // Send request to the resolved backend
    let mut resp = send_to_backend(req, &backend_config)?;

    // Add security and cache headers
    add_security_headers(&mut resp);
    add_cache_headers(&mut resp, &path);

    Ok(resp)
}

#[fastly::main]
fn main(req: Request) -> Result<Response, Error> {
    // Log service version info
    println!(
        "Edge Router Service - Processing request: {} {}",
        req.get_method(),
        req.get_path()
    );

    handle_request(req)
}